<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  :root{
    --bg:#0b0c10; --panel:#15171f; --edge:#242735; --text:#e6e8ef;
    --accent:#7cff3a;
  }
  *{box-sizing:border-box}
  html,body{height:100%}
  body{
    margin:0; background:radial-gradient(1200px 800px at 50% -10%,#161a26,#0b0c10 60%);
    color:var(--text); font-family:ui-sans-serif,system-ui,-apple-system,Segoe UI,Roboto,Arial,sans-serif;
    display:flex; flex-direction:column; align-items:center; justify-content:center;
    min-height:100%; padding:24px; gap:18px;
  }
  h1{
    margin:0; font-size:18px; font-weight:600; letter-spacing:.12em; text-transform:uppercase;
    color:#aab0c4;
  }
  .stage{
    background:var(--panel); border:1px solid var(--edge); border-radius:14px;
    padding:14px; box-shadow:0 20px 60px rgba(0,0,0,.55), inset 0 1px 0 rgba(255,255,255,.03);
  }
  canvas#sand{
    display:block; width:480px; height:480px; image-rendering:pixelated;
    background:#050609; border-radius:8px; cursor:crosshair; touch-action:none;
  }
  .toolbar{
    display:flex; flex-wrap:wrap; gap:10px; align-items:center; justify-content:center;
    max-width:520px;
  }
  button{
    appearance:none; border:1px solid var(--edge); background:#1b1e29; color:var(--text);
    padding:9px 14px; border-radius:10px; font-size:13px; font-weight:600; cursor:pointer;
    display:flex; align-items:center; gap:8px; transition:transform .06s ease, border-color .15s, background .15s;
  }
  button:hover{border-color:#3a3f55}
  button:active{transform:translateY(1px)}
  button.mat .dot{width:12px; height:12px; border-radius:3px; box-shadow:inset 0 0 0 1px rgba(0,0,0,.35)}
  button.active{border-color:var(--accent); background:#20261c; box-shadow:0 0 0 1px var(--accent) inset}
  #clear{border-color:#4a2530; background:#241318; color:#ffb3c0}
  #clear:hover{border-color:#7a3a48}
  .brush{display:flex; align-items:center; gap:8px; font-size:12px; color:#9aa1b6}
  input[type=range]{accent-color:var(--accent)}
  .hint{font-size:11px; color:#6a melamine;color:#6b7288}
</style>
</head>
<body>
  <h1>Falling&nbsp;Sand</h1>
  <div class="stage">
    <canvas id="sand" width="120" height="120"></canvas>
  </div>
  <div class="toolbar">
    <button class="mat" id="mat-sand"><span class="dot" style="background:#d9b76a"></span>Sand</button>
    <button class="mat" id="mat-water"><span class="dot" style="background:#3a7bd5"></span>Water</button>
    <button class="mat" id="mat-wall"><span class="dot" style="background:#767a8c"></span>Wall</button>
    <button class="mat" id="mat-acid"><span class="dot" style="background:#7cff3a"></span>Acid</button>
    <button class="mat" id="mat-empty"><span class="dot" style="background:#0a0a0f;border:1px solid #333"></span>Eraser</button>
    <button id="clear">Clear</button>
    <label class="brush">Brush
      <input type="range" id="brush" min="1" max="6" value="2">
    </label>
  </div>

<script>
(function(){
  "use strict";

  // ---- material codes ----
  const EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
  const NAME_TO_CODE = {empty:EMPTY, sand:SAND, water:WATER, wall:WALL, acid:ACID};
  const CODE_TO_NAME = ["empty","sand","water","wall","acid"];
  const COLORS = {
    [EMPTY]:[8,9,15],
    [SAND]:[217,183,106],
    [WATER]:[58,123,213],
    [WALL]:[118,122,140],
    [ACID]:[124,255,58],
  };

  const W=120, H=120;
  const grid = new Uint8Array(W*H);   // grid[y*W+x]
  const moved = new Uint8Array(W*H);  // per-step guard

  function idx(x,y){ return y*W+x; }
  function inBounds(x,y){ return x>=0 && x<W && y>=0 && y<H; }

  // ---- simulation step: process bottom-row-up so each particle moves <=1 cell ----
  function step(){
    moved.fill(0);
    for(let y=H-1; y>=0; y--){
      for(let x=0; x<W; x++){
        const i = idx(x,y);
        if(moved[i]) continue;
        const m = grid[i];
        if(m===EMPTY || m===WALL) continue;
        if(m===SAND) stepSand(x,y,i);
        else if(m===WATER) stepWater(x,y,i);
        else if(m===ACID) stepAcid(x,y,i);
      }
    }
  }

  function stepSand(x,y,i){
    if(y===H-1) return;                 // bottom boundary
    const bi = idx(x,y+1), bm = grid[bi];
    if(bm===EMPTY){                     // fall straight down
      grid[bi]=SAND; grid[i]=EMPTY; moved[bi]=1; return;
    }
    if(bm===WATER || bm===ACID){        // sink: swap with lighter fluid
      grid[bi]=SAND; grid[i]=bm; moved[bi]=1; return;
    }
    // blocked: slide diagonally, randomized order
    const first = Math.random()<0.5 ? -1 : 1;
    for(const dx of [first,-first]){
      const nx=x+dx;
      if(nx<0||nx>=W) continue;
      const di=idx(nx,y+1);
      if(grid[di]===EMPTY){ grid[di]=SAND; grid[i]=EMPTY; moved[di]=1; return; }
    }
  }

  function stepWater(x,y,i){
    if(y<H-1){
      const bi=idx(x,y+1);
      if(grid[bi]===EMPTY){ grid[bi]=WATER; grid[i]=EMPTY; moved[bi]=1; return; }
      const first = Math.random()<0.5 ? -1 : 1;
      for(const dx of [first,-first]){
        const nx=x+dx;
        if(nx<0||nx>=W) continue;
        const di=idx(nx,y+1);
        if(grid[di]===EMPTY){ grid[di]=WATER; grid[i]=EMPTY; moved[di]=1; return; }
      }
    }
    // can't fall: spread horizontally into empty, randomized
    const first = Math.random()<0.5 ? -1 : 1;
    for(const dx of [first,-first]){
      const nx=x+dx;
      if(nx<0||nx>=W) continue;
      const ni=idx(nx,y);
      if(grid[ni]===EMPTY){ grid[ni]=WATER; grid[i]=EMPTY; moved[ni]=1; return; }
    }
  }

  function stepAcid(x,y,i){
    if(y<H-1){
      const bi=idx(x,y+1), bm=grid[bi];
      if(bm===SAND || bm===WALL){       // dissolve below — both consumed
        grid[bi]=EMPTY; grid[i]=EMPTY; return;
      }
      if(bm===EMPTY){ grid[bi]=ACID; grid[i]=EMPTY; moved[bi]=1; return; }
      if(bm===WATER){ grid[bi]=ACID; grid[i]=WATER; moved[bi]=1; return; }
      // diagonal fall
      const first = Math.random()<0.5 ? -1 : 1;
      for(const dx of [first,-first]){
        const nx=x+dx;
        if(nx<0||nx>=W) continue;
        const di=idx(nx,y+1);
        if(grid[di]===EMPTY){ grid[di]=ACID; grid[i]=EMPTY; moved[di]=1; return; }
      }
    }
    // dissolve a solid beside it — randomized
    const first = Math.random()<0.5 ? -1 : 1;
    for(const dx of [first,-first]){
      const nx=x+dx;
      if(nx<0||nx>=W) continue;
      const ni=idx(nx,y), nm=grid[ni];
      if(nm===SAND || nm===WALL){ grid[ni]=EMPTY; grid[i]=EMPTY; return; }
    }
    // otherwise spread horizontally into empty
    for(const dx of [first,-first]){
      const nx=x+dx;
      if(nx<0||nx>=W) continue;
      const ni=idx(nx,y);
      if(grid[ni]===EMPTY){ grid[ni]=ACID; grid[i]=EMPTY; moved[ni]=1; return; }
    }
  }

  // ---- rendering ----
  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");
  const img = ctx.createImageData(W,H);

  function draw(){
    const d = img.data;
    for(let p=0, c=0; p<grid.length; p++, c+=4){
      const col = COLORS[grid[p]];
      d[c]=col[0]; d[c+1]=col[1]; d[c+2]=col[2]; d[c+3]=255;
    }
    ctx.putImageData(img,0,0);
  }

  function frame(){
    step();
    draw();
    requestAnimationFrame(frame);
  }

  // ---- programmatic API ----
  window.sim = {
    w: W,
    h: H,
    tick(n){ n = (n|0); for(let k=0;k<n;k++) step(); },
    get(x,y){ if(!inBounds(x,y)) return "empty"; return CODE_TO_NAME[grid[idx(x,y)]]; },
    set(x,y,material){
      const code = NAME_TO_CODE[material];
      if(code===undefined || !inBounds(x,y)) return;
      grid[idx(x,y)] = code;
    },
    clear(){ grid.fill(EMPTY); },
  };

  // ---- UI: material selection ----
  let current = SAND;
  const matButtons = {
    "mat-sand":SAND, "mat-water":WATER, "mat-wall":WALL, "mat-acid":ACID, "mat-empty":EMPTY
  };
  function selectMat(id){
    current = matButtons[id];
    for(const bid in matButtons){
      document.getElementById(bid).classList.toggle("active", bid===id);
    }
  }
  for(const bid in matButtons){
    document.getElementById(bid).addEventListener("click", ()=>selectMat(bid));
  }
  selectMat("mat-sand");

  document.getElementById("clear").addEventListener("click", ()=>window.sim.clear());

  const brushInput = document.getElementById("brush");
  let brush = parseInt(brushInput.value,10);
  brushInput.addEventListener("input", ()=>{ brush = parseInt(brushInput.value,10); });

  // ---- painting ----
  let painting = false;

  function paintAt(clientX, clientY){
    const r = canvas.getBoundingClientRect();
    const gx = Math.floor((clientX - r.left) / r.width  * W);
    const gy = Math.floor((clientY - r.top ) / r.height * H);
    const rad = brush - 1;
    for(let dy=-rad; dy<=rad; dy++){
      for(let dx=-rad; dx<=rad; dx++){
        if(dx*dx+dy*dy > rad*rad + rad) continue; // roughly circular
        const x=gx+dx, y=gy+dy;
        if(inBounds(x,y)) grid[idx(x,y)] = current;
      }
    }
  }

  canvas.addEventListener("pointerdown", (e)=>{
    painting=true; canvas.setPointerCapture(e.pointerId); paintAt(e.clientX,e.clientY);
  });
  canvas.addEventListener("pointermove", (e)=>{
    if(painting) paintAt(e.clientX,e.clientY);
  });
  const stop = ()=>{ painting=false; };
  canvas.addEventListener("pointerup", stop);
  canvas.addEventListener("pointercancel", stop);
  canvas.addEventListener("pointerleave", stop);

  // start
  draw();
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
